package rageval

import (
	"bytes"
	"compress/gzip"
	"encoding/base64"
	"errors"
	"image"
	"image/color"
	"image/draw"
	"image/jpeg"
	"image/png"
	"io"
	"strings"

	"golang.org/x/image/font"
	"golang.org/x/image/font/basicfont"
	"golang.org/x/image/math/fixed"
)

func decodeFixtureAsset(encoded string, compressed bool) ([]byte, error) {
	compact := strings.NewReplacer("\n", "", "\r", "", " ", "", "\t", "").Replace(encoded)
	payload, err := base64.StdEncoding.DecodeString(compact)
	if err != nil || !compressed {
		return payload, err
	}
	reader, err := gzip.NewReader(bytes.NewReader(payload))
	if err != nil {
		return nil, err
	}
	defer reader.Close()
	return io.ReadAll(io.LimitReader(reader, 1<<20))
}

func fixturePNG() ([]byte, error) {
	var payload bytes.Buffer
	err := png.Encode(&payload, fixtureSemanticImage(
		color.RGBA{R: 244, G: 247, B: 250, A: 255},
		color.RGBA{R: 255, G: 212, B: 59, A: 255},
		"PUBLICATION BARRIER",
	))
	return payload.Bytes(), err
}

func fixtureJPEG() ([]byte, error) {
	var payload bytes.Buffer
	err := jpeg.Encode(&payload, fixtureSemanticImage(
		color.RGBA{R: 244, G: 247, B: 250, A: 255},
		color.RGBA{R: 202, G: 45, B: 45, A: 255},
		"VERIFIER",
	), &jpeg.Options{Quality: 92})
	return payload.Bytes(), err
}

func fixtureSemanticImage(background, accent color.RGBA, label string) *image.RGBA {
	const scale = 3
	small := image.NewRGBA(image.Rect(0, 0, 320, 180))
	draw.Draw(small, small.Bounds(), image.NewUniform(background), image.Point{}, draw.Src)
	draw.Draw(small, image.Rect(35, 50, 285, 130), image.NewUniform(accent), image.Point{}, draw.Src)
	textWidth := font.MeasureString(basicfont.Face7x13, label).Ceil()
	textColor := color.RGBA{R: 20, G: 28, B: 38, A: 255}
	if int(accent.R)+int(accent.G)+int(accent.B) < 300 {
		textColor = color.RGBA{R: 255, G: 255, B: 255, A: 255}
	}
	(&font.Drawer{
		Dst: small, Src: image.NewUniform(textColor), Face: basicfont.Face7x13,
		Dot: fixed.P((320-textWidth)/2, 95),
	}).DrawString(label)
	large := image.NewRGBA(image.Rect(0, 0, 320*scale, 180*scale))
	for y := 0; y < large.Bounds().Dy(); y++ {
		for x := 0; x < large.Bounds().Dx(); x++ {
			large.SetRGBA(x, y, small.RGBAAt(x/scale, y/scale))
		}
	}
	return large
}

func fixtureWebP() ([]byte, error) {
	payload, err := decodeFixtureAsset(fixtureWebPBase64, false)
	if err != nil || len(payload) < 12 || string(payload[:4]) != "RIFF" || string(payload[8:12]) != "WEBP" {
		return nil, errors.New("invalid frozen WebP fixture")
	}
	return payload, nil
}

